import { useNavigate } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import { FaUserShield } from 'react-icons/fa';
import axios from 'axios';
import './Home.css'; 

function Home() {
    const [showProfile, setShowProfile] = useState(false);
    const [user, setUser] = useState(null);
    const navigate = useNavigate();
    const [stats, setStats] = useState({
       totalPredictions: 0,
       avgSalary: 0,
       bestModelAccuracy: 0,
       lastPrediction: 0
});
   useEffect(() => {

  axios.get('http://localhost:5000/stats')  
       .then(res => {
           setStats({
             totalPredictions: res.data.totalPredictions,
             avgSalary: res.data.avgSalary,
             bestModelAccuracy: res.data.bestModelAccuracy,
           });
       })
       .catch(err => console.log(err));
}, []);
    
    useEffect(() => {
      const  storedUser = localStorage.getItem("user");
        if (storedUser) {
           setUser(JSON.parse(storedUser));
        } else {
            navigate('/login');
        }
    }, [navigate]); 

    const handleLogout = () => {
        localStorage.clear();
        navigate('/login');
    };
    const handleNewPrediction = () => {
      navigate('/predict')
    }
    
  return (
    <div className="home-container">
      <nav className="navbar">
        <div className="left-section">
          <div className="admin-nav-link" onClick={() => navigate('/adminlogin')}>
            <FaUserShield size={20} />
            <span>Admin Login</span>  
          </div>
        </div>
        <div className="right-section">
          <div className="profile-circle"
          onClick={() =>setShowProfile(!showProfile)}>
            <span>{user?.name?.charAt(0) || "P"}</span>
          </div>
         {showProfile && (
            <div className='profile-card'>
               <center><h3>Profile 👤</h3></center> 
                <p><b>Name:</b> {user?.name}</p>
                <p><b>Email:</b> {user?.email}</p>
                <p><b>Password:</b>{"*".repeat(user?.password?.length || 8)}</p>
                </div>
         )} 
  
          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </nav>

      <div className="main-content">
      <h2>"Know your worth,predict with Confidence!!! 🚀"</h2>
      <button className='new-prediction-btn' onClick = {handleNewPrediction}>New Salary Prediction</button>
               <div className="stats-container">
  <div className="stat-card">
    <div onClick={() => navigate("/my-history")}>
    <h3>Total Predictions</h3>
    <p>{stats.totalPredictions}</p>
  </div>
  </div>
  <div className="stat-card">
    <h3>Average Salary</h3>
    <p>${stats.avgSalary}</p>
  </div>
  <div className="stat-card">
    <h3>Best Model Accuracy</h3>
    <p>{stats.bestModelAccuracy}%</p>
  </div>
</div>
      </div>
    </div>
  );
};

export default Home;
